import React from "react";
import "../styles/contact.css";
import { FaGithub, FaLinkedin, FaInstagram, FaFacebook } from "react-icons/fa";

const Contact = () => {
  return (
    <section className="contact-section" id="contact">

      <div className="section-title">
        <h2>Contact Me</h2>
        <div className="underline"></div>
      </div>

      <div className="contact-container">

        {/* LEFT SIDE */}
        <div className="contact-info">
          <h3>Get In Touch</h3>
          <p>Feel free to contact me for any project or collaboration.</p>

          <p><strong>Email:</strong> nijbhavsar4433@gmail.com</p>
          <p><strong>Phone:</strong> +91 9313234412</p>
          <p><strong>Location:</strong> Pratapnagar, Navsari, India</p>

          <div className="social-icons">
            <a href="https://github.com/yourusername"><FaGithub /></a>
            <a href="https://linkedin.com/in/yourusername"><FaLinkedin /></a>
            <a href="https://instagram.com/yourusername"><FaInstagram /></a>
            <a href="https://facebook.com/yourusername"><FaFacebook /></a>
          </div>
        </div>

        {/* RIGHT SIDE */}
        <div className="contact-form">
          <form>
            <input type="text" placeholder="Your Name" required />
            <input type="email" placeholder="Your Email" required />
            <textarea placeholder="Your Message" required></textarea>

            <button type="submit">Send Message</button>
          </form>
        </div>

      </div>

    </section>
  );
};

export default Contact;
